import { useResizableVerticalPanelsContext } from './resizable-vertical-panels-context';
import { RouterSettings } from './router-settings';
import { StepInfo } from './step-info';
import { useStepSettingsContext } from './step-settings-context';

const StepSettingsContainer = () => {
  const { selectedStep, pieceModel, formSchema } = useStepSettingsContext();
  const { project } = projectCollectionUtils.useCurrentProject();
  const [
    readonly,
    exitStepSettings,
    applyOperation,
    saving,
    flowVersion,
    selectedBranchIndex,
    setSelectedBranchIndex,
    run,
  ] = useBuilderStateContext((state) => [
    state.readonly,
    state.exitStepSettings,
    state.applyOperation,
    state.saving,
    state.flowVersion,
    state.selectedBranchIndex,
    state.setSelectedBranchIndex,
    state.run,
  ]);

  const { stepMetadata } = stepsHooks.useStepMetadata({
    step: selectedStep,
  });

  const selectedStepRef = useRef(selectedStep);
  selectedStepRef.current = selectedStep;

  const currentValuesRef = useRef<FlowAction | FlowTrigger>(selectedStep);
  const form = useForm<FlowAction | FlowTrigger>({
    mode: 'all',
    disabled: readonly,
    reValidateMode: 'onChange',
    defaultValues: selectedStep,
    resetOptions: {
      keepDefaultValues: false,
      keepDirtyValues: true,
    },
    resolver: async (values, context, options) => {
      const result = await (
        zodResolver(formSchema) as unknown as Resolver<FlowAction | FlowTrigger>
      )(values, context, options);

      const cleanedNewValues = formUtils.removeUndefinedFromInput(values);
      const cleanedCurrentValues = formUtils.removeUndefinedFromInput(
        currentValuesRef.current,
      );
      const valid = Object.keys(result.errors).length === 0;
      cleanedNewValues.valid = valid;
      if (
        cleanedNewValues.type === FlowTriggerType.EMPTY ||
        (isNil(pieceModel) &&
          (cleanedNewValues.type === FlowActionType.PIECE ||
            cleanedNewValues.type === FlowTriggerType.PIECE))
      ) {
        return result;
      }
      if (
        deepEqual(
          stripSampleData(cleanedNewValues),
          stripSampleData(cleanedCurrentValues),
        )
      ) {
        return result;
      }
      //We need to copy the object because the form is using the same object reference
      currentValuesRef.current = JSON.parse(JSON.stringify(cleanedNewValues));
      if (cleanedNewValues.type === FlowTriggerType.PIECE) {
        applyOperation({
          type: FlowOperationType.UPDATE_TRIGGER,
          request: {
            ...cleanedNewValues,
            valid,
          },
        });
      } else {
        applyOperation({
          type: FlowOperationType.UPDATE_ACTION,
          request: {
            ...cleanedNewValues,
            valid,
          },
        });
      }
      return result;
    },
  });

  const sidebarHeaderContainerRef = useRef<HTMLDivElement>(null);
  const modifiedStep = form.getValues();
  const isManualTrigger =
    modifiedStep.type === FlowTriggerType.PIECE &&
    pieceSelectorUtils.isManualTrigger({
      pieceName: modifiedStep.settings.pieceName,
      triggerName: modifiedStep.settings.triggerName ?? '',
    });
  const showGenerateSampleData = !readonly && !isManualTrigger;
  const showStepInputOutFromRun = !isNil(run) && !isManualTrigger;

  const [isEditingStepOrBranchName, setIsEditingStepOrBranchName] =
    useState(false);
  const showActionErrorHandlingForm =
    [FlowActionType.CODE, FlowActionType.PIECE].includes(
      modifiedStep.type as FlowActionType,
    ) && !isNil(stepMetadata);

  const runAgentStep =
    modifiedStep.settings.pieceName === '@activepieces/piece-ai' &&
    modifiedStep.settings.actionName === 'run_agent';

  useEffect(() => {
    //RHF doesn't automatically trigger validation when the form is rendered, so we need to trigger it manually
    form.trigger();
  }, []);

  const { height, setHeight } = useResizableVerticalPanelsContext();

  return (
    <Form {...form}>
      <form
        onSubmit={(e) => e.preventDefault()}
        onChange={(e) => e.preventDefault()}
        className="w-full h-full"
      >
        <div ref={sidebarHeaderContainerRef}>
          <SidebarHeader onClose={() => exitStepSettings()}>
            <EditableStepName
              selectedBranchIndex={selectedBranchIndex}
              setDisplayName={(value) => {
                form.setValue('displayName', value, {
                  shouldValidate: true,
                });
              }}
              readonly={readonly}
              displayName={modifiedStep.displayName}
              branchName={
                !isNil(selectedBranchIndex)
                  ? modifiedStep.settings.branches?.[selectedBranchIndex]
                      ?.branchName
                  : undefined
              }
              setBranchName={(value) => {
                if (!isNil(selectedBranchIndex)) {
                  form.setValue(
                    `settings.branches[${selectedBranchIndex}].branchName`,
                    value,
                    {
                      shouldValidate: true,
                    },
                  );
                }
              }}
              setSelectedBranchIndex={setSelectedBranchIndex}
              isEditingStepOrBranchName={isEditingStepOrBranchName}
              setIsEditingStepOrBranchName={setIsEditingStepOrBranchName}
            ></EditableStepName>
          </SidebarHeader>
          <Separator className="w-full h-px" />
        </div>

        <DynamicPropertiesProvider
          key={`${selectedStep.name}-${selectedStep.type}`}
        >
          <ResizablePanelGroup orientation="vertical">
            <ResizablePanel className="min-h-[80px]">
              <ScrollArea className="h-full">
                <div className="w-full my-3 px-3">
                  {stepMetadata && <StepInfo step={selectedStep} />}
                </div>
                <div
                  className={cn(
                    'flex flex-col px-4 pb-6',
                    GAP_SIZE_FOR_STEP_SETTINGS,
                  )}
                >
                  {modifiedStep.type === FlowActionType.LOOP_ON_ITEMS && (
                    <LoopsSettings readonly={readonly}></LoopsSettings>
                  )}
                  {modifiedStep.type === FlowActionType.CODE && (
                    <CodeSettings readonly={readonly}></CodeSettings>
                  )}
                  {modifiedStep.type === FlowActionType.PIECE &&
                    runAgentStep &&
                    modifiedStep && (
                      <AgentSettings
                        step={modifiedStep}
                        flowId={flowVersion.flowId}
                        readonly={readonly}
                      />
                    )}
                  {modifiedStep.type === FlowActionType.PIECE &&
                    !runAgentStep &&
                    modifiedStep && (
                      <PieceSettings
                        step={modifiedStep}
                        flowId={flowVersion.flowId}
                        readonly={readonly}
                      ></PieceSettings>
                    )}
                  {modifiedStep.type === FlowActionType.ROUTER &&
                    modifiedStep && (
                      <RouterSettings readonly={readonly}></RouterSettings>
                    )}
                  {modifiedStep.type === FlowTriggerType.PIECE &&
                    modifiedStep && (
                      <PieceSettings
                        step={modifiedStep}
                        flowId={flowVersion.flowId}
                        readonly={readonly}
                      ></PieceSettings>
                    )}
                  {showActionErrorHandlingForm && (
                    <ActionErrorHandlingForm
                      hideContinueOnFailure={
                        stepMetadata.type === FlowActionType.PIECE
                          ? stepMetadata.errorHandlingOptions?.continueOnFailure
                              ?.hide
                          : false
                      }
                      disabled={readonly}
                      hideRetryOnFailure={
                        stepMetadata.type === FlowActionType.PIECE
                          ? stepMetadata.errorHandlingOptions?.retryOnFailure
                              ?.hide
                          : false
                      }
                    ></ActionErrorHandlingForm>
                  )}
                </div>
              </ScrollArea>
            </ResizablePanel>

            {(showGenerateSampleData || showStepInputOutFromRun) && (
              <>
                <ResizableHandle withHandle={true} />
                <ResizablePanel
                  defaultSize={`${height}%`}
                  onResize={(panelSize) => setHeight(panelSize.asPercentage)}
                  className="min-h-[130px]"
                >
                  <ScrollArea
                    className="h-[calc(100%-35px)]"
                    viewPortClassName="h-full"
                  >
                    {showGenerateSampleData && (
                      <TestStepContainer
                        type={modifiedStep.type}
                        flowId={flowVersion.flowId}
                        flowVersionId={flowVersion.id}
                        projectId={project?.id}
                        isSaving={saving}
                      ></TestStepContainer>
                    )}
                    {showStepInputOutFromRun && (
                      <FlowStepInputOutput></FlowStepInputOutput>
                    )}
                  </ScrollArea>
                </ResizablePanel>
              </>
            )}
          </ResizablePanelGroup>
        </DynamicPropertiesProvider>
      </form>
    </Form>
  );
};
StepSettingsContainer.displayName = 'StepSettingsContainer';
export { StepSettingsContainer };
const stripSampleData = (step: FlowAction | FlowTrigger) => {
  const { sampleData: _, ...settingsWithoutSampleData } = step.settings;
  const { lastUpdatedDate: __, ...stepWithoutMetadata } = step;

  return { ...stepWithoutMetadata, settings: settingsWithoutSampleData };
};

import {
  FlowActionType,
  FlowOperationRequest,
  FlowOperationType,
  flowStructureUtil,
  FlowVersion,
  isNil,
  RouterAction,
  RouterExecutionType,
} from '@activepieces/shared';
import { useReactFlow } from '@xyflow/react';
import { t } from 'i18next';
import { Split } from 'lucide-react';
import { memo, useEffect } from 'react';
import { useFieldArray, useFormContext } from 'react-hook-form';

import { FormField, FormItem } from '../../../../components/ui/form';
import { Label } from '../../../../components/ui/label';
import {
  Select,
  SelectValue,
  SelectTrigger,
  SelectContent,
  SelectItem,
} from '../../../../components/ui/select';
import { useBuilderStateContext } from '../../builder-hooks';
import { flowCanvasUtils } from '../../flow-canvas/utils/flow-canvas-utils';
import { BranchSettings } from '../branch-settings';

import { BranchesList } from './branches-list';
import BranchesToolbar from './branches-toolbar';

export const RouterSettings = memo(({ readonly }: { readonly: boolean }) => {
  const [
    step,
    applyOperation,
    setSelectedBranchIndex,
    selectedBranchIndex,
    addOperationListener,
    removeOperationListener,
  ] = useBuilderStateContext((state) => [
    flowStructureUtil.getActionOrThrow(
      state.selectedStep!,
      state.flowVersion.trigger,
    ) as RouterAction,
    state.applyOperation,
    state.setSelectedBranchIndex,
    state.selectedBranchIndex,
    state.addOperationListener,
    state.removeOperationListener,
  ]);
  const { fitView } = useReactFlow();

  const { control, setValue, formState } =
    useFormContext<Omit<RouterAction, 'children' | 'nextAction'>>();

  //To validate array items we need to use form.trigger()
  const { insert, remove, move } = useFieldArray({
    control,
    name: 'settings.branches',
  });
  const form = useFormContext<Omit<RouterAction, 'children' | 'nextAction'>>();
  const deleteBranch = (index: number) => {
    applyOperation({
      type: FlowOperationType.DELETE_BRANCH,
      request: {
        stepName: step.name,
        branchIndex: index,
      },
    });

    setSelectedBranchIndex(null);
    fitView(flowCanvasUtils.createFocusStepInGraphParams(step.name));
  };

  useEffect(() => {
    const operationListener = (
      flowVersion: FlowVersion,
      operation: FlowOperationRequest,
    ) => {
      switch (operation.type) {
        case FlowOperationType.DELETE_BRANCH: {
          if (operation.request.stepName !== step.name) {
            return;
          }
          remove(operation.request.branchIndex);
          break;
        }
        case FlowOperationType.DUPLICATE_BRANCH:
        case FlowOperationType.ADD_BRANCH: {
          if (operation.request.stepName !== step.name) return;
          const updatedStep = flowStructureUtil.getActionOrThrow(
            operation.request.stepName,
            flowVersion.trigger,
          );
          if (updatedStep.type !== FlowActionType.ROUTER) {
            console.error(
              `Trying to duplicate a branch on a none router step! ${operation.request.stepName}`,
            );
            return;
          }
          const branch =
            updatedStep.settings.branches[operation.request.branchIndex];
          if (operation.type === FlowOperationType.DUPLICATE_BRANCH) {
            insert(operation.request.branchIndex + 1, {
              ...branch,
              branchName: `${branch.branchName} Copy`,
            });
          } else {
            insert(
              updatedStep.settings.branches.length - 1,
              flowStructureUtil.createBranch(
                `Branch ${updatedStep.settings.branches.length}`,
                undefined,
              ),
            );
          }
          form.trigger();
          break;
        }
        case FlowOperationType.MOVE_BRANCH: {
          if (operation.request.stepName !== step.name) return;
          move(
            operation.request.sourceBranchIndex,
            operation.request.targetBranchIndex,
          );
          break;
        }
      }
    };

    addOperationListener(operationListener);
    return () => removeOperationListener(operationListener);
  }, []);

  return (
    <>
      {isNil(selectedBranchIndex) && (
        <FormField
          control={control}
          name="settings.executionType"
          render={({ field }) => (
            <FormItem>
              <Label>{t('Execute')}</Label>
              <Select
                disabled={field.disabled}
                onValueChange={field.onChange}
                value={field.value}
              >
                <SelectTrigger>
                  <SelectValue placeholder={t('Execute')} />
                </SelectTrigger>

                <SelectContent>
                  <SelectItem
                    value={`${RouterExecutionType.EXECUTE_FIRST_MATCH}`}
                  >
                    {t('Only the first (left) matching branch')}
                  </SelectItem>
                  <SelectItem
                    value={`${RouterExecutionType.EXECUTE_ALL_MATCH}`}
                  >
                    {t('All matching paths from left to right')}
                  </SelectItem>
                </SelectContent>
              </Select>
            </FormItem>
          )}
        ></FormField>
      )}

      {isNil(selectedBranchIndex) && (
        <div>
          <div className="flex gap-2 mb-2 items-center">
            <Split className="w-4 h-4 rotate-180"></Split>
            <Label>{t('Branches')}</Label>
          </div>

          <BranchesList
            errors={(formState.errors.settings?.branches as unknown[]) ?? []}
            readonly={readonly}
            step={step}
            branchNameChanged={(index, name) => {
              setValue(`settings.branches.${index}.branchName` as const, name, {
                shouldValidate: true,
              });
            }}
            deleteBranch={deleteBranch}
            moveBranch={({ sourceIndex, targetIndex }) => {
              applyOperation({
                type: FlowOperationType.MOVE_BRANCH,
                request: {
                  stepName: step.name,
                  sourceBranchIndex: sourceIndex,
                  targetBranchIndex: targetIndex,
                },
              });
            }}
            duplicateBranch={(index) => {
              applyOperation({
                type: FlowOperationType.DUPLICATE_BRANCH,
                request: {
                  stepName: step.name,
                  branchIndex: index,
                },
              });
              setSelectedBranchIndex(index + 1);
            }}
            setSelectedBranchIndex={(index) => {
              setSelectedBranchIndex(index);
              if (step.children[index]) {
                fitView(
                  flowCanvasUtils.createFocusStepInGraphParams(
                    step.children[index].name,
                  ),
                );
              } else {
                fitView(
                  flowCanvasUtils.createFocusStepInGraphParams(
                    `${step.name}-big-add-button-${step.name}-branch-${index}-start-edge`,
                  ),
                );
              }
            }}
          ></BranchesList>
          {!readonly && (
            <div className="mt-2">
              <BranchesToolbar
                addButtonClicked={() => {
                  applyOperation({
                    type: FlowOperationType.ADD_BRANCH,
                    request: {
                      stepName: step.name,
                      branchIndex: step.settings.branches.length - 1,
                      branchName: `Branch ${step.settings.branches.length}`,
                    },
                  });

                  setSelectedBranchIndex(step.settings.branches.length - 1);
                }}
              ></BranchesToolbar>
            </div>
          )}
        </div>
      )}

      {!isNil(selectedBranchIndex) && (
        <BranchSettings
          readonly={readonly}
          key={`settings.branches[${selectedBranchIndex}].conditions`}
          branchIndex={selectedBranchIndex}
        ></BranchSettings>
      )}
    </>
  );
});

RouterSettings.displayName = 'RouterSettings';

import {
  BadgeAwarded,
  BADGES,
  ApFlagId,
  WebsocketClientEvent,
} from '@activepieces/shared';
import confetti from 'canvas-confetti';
import { Trophy } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';
import { toast } from 'sonner';

import { useSocket } from '@/components/providers/socket-provider';
import { flagsHooks } from '@/hooks/flags-hooks';
import { userHooks } from '@/hooks/user-hooks';

import { AccountSettingsDialog } from './account-settings';

export const BadgeCelebrate = () => {
  const socket = useSocket();
  const { refetch } = userHooks.useCurrentUser();
  const cleanupRef = useRef<() => void>(undefined);
  const { data: showBadges } = flagsHooks.useFlag<boolean>(
    ApFlagId.SHOW_BADGES,
  );
  const isCelebrating = useRef(false);
  const celebrationTimeout = useRef<number | null>(null);
  const [showAccountSettings, setShowAccountSettings] = useState(false);
  const openAccountSettingsRef = useRef(() => setShowAccountSettings(true));

  useEffect(() => {
    if (!socket || !showBadges) return;
    if (cleanupRef.current) {
      cleanupRef.current();
    }

    const handleBadgeAwarded = (data: BadgeAwarded) => {
      const badge = BADGES[data.badge as keyof typeof BADGES];
      if (!badge) {
        return;
      }

      const badgeTitle = badge?.title;
      const badgeDescription = badge?.description;
      const badgeImageUrl = badge?.imageUrl;

      toast.custom(
        () => (
          <BadgeToast
            imageUrl={badgeImageUrl}
            title={badgeTitle}
            description={badgeDescription}
            onClick={openAccountSettingsRef.current}
          />
        ),
        {
          duration: 10000,
          className:
            'bg-background border border-border rounded-xl shadow-lg p-3',
        },
      );

      refetch();
      if (isCelebrating.current) {
        return;
      }
      isCelebrating.current = true;

      const duration = 6000;
      const animationEnd = Date.now() + duration;
      const interval = setInterval(() => {
        const timeLeft = animationEnd - Date.now();

        if (timeLeft <= 0) {
          clearInterval(interval);
          return;
        }
        const defaults = {
          startVelocity: 30,
          spread: 360,
          ticks: 60,
          zIndex: 9999,
        };
        const particleCount = 50 * (timeLeft / duration);

        confetti({
          ...defaults,
          particleCount,
          origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 },
        });
        confetti({
          ...defaults,
          particleCount,
          origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 },
        });
      }, 250);

      // Set a timeout to reset the celebrating flag when finished
      if (celebrationTimeout.current) {
        clearTimeout(celebrationTimeout.current);
      }
      celebrationTimeout.current = window.setTimeout(() => {
        isCelebrating.current = false;
        celebrationTimeout.current = null;
      }, duration);
    };

    socket.on(WebsocketClientEvent.BADGE_AWARDED, handleBadgeAwarded);

    cleanupRef.current = () => {
      socket.off(WebsocketClientEvent.BADGE_AWARDED, handleBadgeAwarded);
      isCelebrating.current = false;
      if (celebrationTimeout.current) {
        clearTimeout(celebrationTimeout.current);
        celebrationTimeout.current = null;
      }
    };

    return cleanupRef.current;
  }, [socket, showBadges]);

  return (
    <AccountSettingsDialog
      open={showAccountSettings}
      onClose={() => setShowAccountSettings(false)}
    />
  );
};

function randomInRange(min: number, max: number) {
  return Math.random() * (max - min) + min;
}

const BadgeToast = ({
  imageUrl,
  title,
  description,
  onClick,
}: {
  imageUrl: string;
  title: string;
  description: string;
  onClick: () => void;
}) => (
