import { AppConnectionScope, PopulatedFlow } from '@activepieces/shared';
import { useMutation } from '@tanstack/react-query';
import { t } from 'i18next';
import { GlobeIcon, WorkflowIcon } from 'lucide-react';
import React, { useState, useMemo } from 'react';
import { FieldErrors, useForm, useWatch } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';

import { SearchableSelect } from '@/components/custom/searchable-select';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { Form, FormField, FormMessage } from '@/components/ui/form';
import { Label } from '@/components/ui/label';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  appConnectionsMutations,
  appConnectionsQueries,
} from '@/features/connections';
import { flowsApi } from '@/features/flows';
import { PieceIconWithPieceName, piecesHooks } from '@/features/pieces';
import { cn } from '@/lib/utils';

type ReplaceConnectionsDialogProps = {
  onConnectionMerged: () => void;
  children: React.ReactNode;
  projectId: string;
};

type FormData = {
  pieceName: string;
  sourceConnections: { id: string; externalId: string };
  replacedWithConnection: { id: string; externalId: string };
};

enum STEP {
  SELECT = 'SELECT',
  CONFIRM = 'CONFIRM',
}

const ReplaceConnectionsDialog = ({
  onConnectionMerged,
  children,
  projectId,
}: ReplaceConnectionsDialogProps) => {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [step, setStep] = useState<STEP>(STEP.SELECT);
  const [affectedFlows, setAffectedFlows] = useState<Array<PopulatedFlow>>([]);
  const { pieces, isLoading: piecesLoading } = piecesHooks.usePieces({});

  const { data: connections, isLoading: connectionsLoading } =
    appConnectionsQueries.useAppConnections({
      request: {
        projectId,
        limit: 1000,
      },
      extraKeys: [projectId, dialogOpen],
      enabled: dialogOpen,
    });

  const { mutate: replaceConnections, isPending: isReplacing } =
    appConnectionsMutations.useReplaceConnections({
      setDialogOpen,
      refetch: onConnectionMerged,
    });

  const { mutate: fetchAffectedFlows, isPending: isFetchingAffectedFlows } =
    useMutation({
      mutationFn: async (externalId: string) => {
        const response = await flowsApi.list({
          projectId: projectId,
          connectionExternalIds: [externalId],
          cursor: undefined,
          limit: 1000,
        });
        return response;
      },
      onSuccess: (data) => {
        setAffectedFlows(data.data);
        setStep(STEP.CONFIRM);
      },
      onError: () => {
        toast.error(t('Error'), {
          description: t('Failed to get affected flows'),
        });
      },
    });

  const form = useForm<FormData>({
    defaultValues: {
      pieceName: '',
      sourceConnections: { id: '', externalId: '' },
      replacedWithConnection: { id: '', externalId: '' },
    },
    mode: 'onSubmit',
    resolver: (values) => {
      const errors: FieldErrors<FormData> = {};

      if (!values.pieceName) {
        errors.pieceName = {
          type: 'required',
          message: t('Please select a piece'),
        };
      }

      if (!values.sourceConnections?.id) {
        errors.sourceConnections = {
          type: 'required',
          message: t('Please select a connection to replace'),
        };
      }

      if (!values.replacedWithConnection?.id) {
        errors.replacedWithConnection = {
          type: 'required',
          message: t('Please select a connection to replace with'),
        };
      }

      return {
        values: Object.keys(errors).length === 0 ? values : {},
        errors,
      };
    },
  });

  const selectedPiece = form.watch('pieceName');

  const connectionPieceNames = new Set(
    connections?.data.map((conn) => conn.pieceName),
  );

  const piecesOptions =
    pieces
      ?.filter(
        (piece) =>
          piece.name !== '@activepieces/piece-mcp' &&
          piece.name !== '@activepieces/piece-webhook' &&
          connectionPieceNames.has(piece.name),
      )
      .map((piece) => ({
        label: piece.displayName,
        value: piece.name,
      })) ?? [];

  const filteredConnections =
    connections?.data.filter((conn) => conn.pieceName === selectedPiece) ?? [];

  const sourceConnectionId = useWatch({
    control: form.control,
    name: 'sourceConnections.id',
  });

  const replacedWithOptions = useMemo(() => {
    return filteredConnections
      .filter((conn) => conn.id !== sourceConnectionId)
      .map((conn) => ({
        label: conn.displayName,
        value: conn.id,
      }));
  }, [filteredConnections, sourceConnectionId]);

  const handleBack = () => {
    setStep(STEP.SELECT);
    setAffectedFlows([]);
  };

  const handleConfirmedSubmit = async (values: FormData) => {
    const isValid = await form.trigger();
    if (!isValid) {
      form.trigger([
        'pieceName',
        'sourceConnections',
        'replacedWithConnection',
      ]);
      return;
    }

    replaceConnections({
      sourceAppConnectionId: values.sourceConnections.id,
      targetAppConnectionId: values.replacedWithConnection.id,
      projectId: projectId,
    });
  };

  const handleDialogOpenChange = (open: boolean) => {
    setDialogOpen(open);
    form.reset();
    setStep(STEP.SELECT);
    setAffectedFlows([]);
  };
  const navigate = useNavigate();

  return (
    <Dialog open={dialogOpen} onOpenChange={handleDialogOpenChange}>
      <DialogTrigger asChild>{children}</DialogTrigger>
      <DialogContent className="flex flex-col">
        <DialogHeader>
          <DialogTitle>
            {step === STEP.SELECT
              ? t('Replace Connections')
              : t('Confirm Replacement')}
          </DialogTitle>
          <DialogDescription>
            {step === STEP.SELECT ? (
              t(
                'This will replace one connection with another connection, existing flows will be changed to use the new connection, and the old connection will be deleted.',
              )
            ) : (
              <>
                {t(
                  'Existing MCP servers will not be changed automatically, you have to reconnect them manually.',
                )}
              </>
            )}
          </DialogDescription>
        </DialogHeader>

        {step === STEP.SELECT ? (
          <Form {...form}>
            <form
              onSubmit={form.handleSubmit((data) =>
                fetchAffectedFlows(data.sourceConnections.externalId),
              )}
              className="flex flex-col gap-4"
            >
              <FormField
                control={form.control}
                name="pieceName"
                render={({ field }) => (
                  <div className="flex flex-col gap-2">
                    <Label>{t('Piece')}</Label>
                    <SearchableSelect
                      value={field.value}
                      onChange={(value) => {
                        field.onChange(value);
                        form.setValue('sourceConnections', {
                          id: '',
                          externalId: '',
                        });
                        form.setValue('replacedWithConnection', {
                          id: '',
                          externalId: '',
                        });
                      }}
                      options={piecesOptions}
                      placeholder={t('Select a piece')}
                      loading={piecesLoading}
                      valuesRendering={(value) => {
                        const piece = pieces?.find((p) => p.name === value);
                        return (
                          <div className="flex gap-2 items-center">
                            <img
                              src={piece!.logoUrl}
                              alt={piece!.displayName}
                              className="w-4 h-4 object-contain"
                            />
                            <span>{piece!.displayName}</span>
                          </div>
                        );
                      }}
                    />
                    <FormMessage />
                  </div>
                )}
              />

              {selectedPiece && (
                <>
                  <FormField
                    control={form.control}
                    name="sourceConnections"
                    render={({ field }) => (
                      <div className="flex flex-col gap-2">
                        <Label>{t('Connection to replace')}</Label>
                        <SearchableSelect
                          value={field.value?.id}
                          loading={connectionsLoading}
                          onChange={(value) => {
                            const selectedConnection = filteredConnections.find(
                              (c) => c.id === value,
                            );
                            field.onChange({
                              id: selectedConnection?.id || '',
                              externalId: selectedConnection?.externalId || '',
                            });
                            form.setValue('replacedWithConnection', {
                              id: '',
                              externalId: '',
                            });
                          }}
                          options={filteredConnections
                            .filter(
                              (conn) =>
                                conn.scope === AppConnectionScope.PROJECT,
                            )
                            .map((conn) => ({
                              label: conn.displayName,
                              value: conn.id,
                            }))}
                          placeholder={t('Choose connection to replace')}
                          valuesRendering={(value) => {
                            const conn = filteredConnections.find(
                              (c) => c.id === value,
                            );
                            return (
                              <div className="flex gap-2 items-center">
                                <PieceIconWithPieceName
                                  pieceName={conn!.pieceName}
                                  size="xs"
                                  border={false}
                                />
                                <span>{conn!.displayName}</span>
                              </div>
                            );
                          }}
                        />
                        <FormMessage />
                      </div>
                    )}
                  />

                  {selectedPiece && (
                    <FormField
                      control={form.control}
                      name="replacedWithConnection"
                      render={({ field }) => (
                        <div className="flex flex-col gap-2">
                          <Label>{t('Replaced With')}</Label>
                          <SearchableSelect
                            value={field.value?.id}
                            loading={connectionsLoading}
                            onChange={(value) => {
                              const selectedConnection =
                                filteredConnections.find((c) => c.id === value);
                              field.onChange({
                                id: selectedConnection?.id || '',
                                externalId:
                                  selectedConnection?.externalId || '',
                              });
                            }}
                            options={replacedWithOptions}
                            placeholder={t('Choose connection to replace with')}
                            valuesRendering={(value) => {
                              const conn = filteredConnections.find(
                                (c) => c.id === value,
                              );
                              return (
                                <div className="flex gap-2 items-center">
                                  <PieceIconWithPieceName
                                    pieceName={conn!.pieceName}
                                    size="xs"
                                    border={false}
                                  />
                                  {conn?.scope ===
                                    AppConnectionScope.PLATFORM && (
                                    <GlobeIcon className="w-4 h-4" />
                                  )}
                                  <span>{conn!.displayName}</span>
                                </div>
                              );
                            }}
                          />
                          <FormMessage />
                        </div>
                      )}
                    />
                  )}
                </>
              )}

              <DialogFooter>
                <DialogClose asChild>
                  <Button type="button" variant="ghost">
                    {t('Cancel')}
                  </Button>
                </DialogClose>
                <Button type="submit" loading={isFetchingAffectedFlows}>
                  {t('Next')}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        ) : (
          <div className="flex flex-col gap-4">
            <ScrollArea
              className={cn(
                'h-[275px]',
                affectedFlows.length === 0 && 'h-[80px]',
              )}
            >
              <div className="flex flex-col gap-2">
                {affectedFlows.length === 0 ? (
                  <span className="text-center text-muted-foreground p-4">
                    {t('No flows will be affected by this change')}
                  </span>
                ) : (
                  affectedFlows.map((flow) => (
                    <div
                      className="flex items-center justify-between"
                      key={flow.id}
                    >
                      <div className="flex items-center gap-2">
                        <WorkflowIcon className="w-5 h-5" />
                        <Button
                          variant="link"
                          className="p-0 h-auto font-medium text-foreground truncate text-base"
                          onClick={() => {
                            navigate(
                              `/projects/${flow.projectId}/flows/${flow.id}`,
                            );
                          }}
                        >
                          {flow.version.displayName}
                        </Button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </ScrollArea>

            <DialogFooter>
              <Button type="button" variant="accent" onClick={handleBack}>
                {t('Back')}
              </Button>
              <Button
                type="button"
                onClick={() => handleConfirmedSubmit(form.getValues())}
                loading={isReplacing}
              >
                {t('Replace')}
              </Button>
            </DialogFooter>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
};

ReplaceConnectionsDialog.displayName = 'ReplaceConnectionsDialog';
export { ReplaceConnectionsDialog };

import { useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

export const AfterImportFlowRedirect = () => {
  const { flowId } = useParams();
  const navigate = useNavigate();
  useEffect(() => {
    navigate(`/flows/${flowId}`, { replace: true });
  }, []);
  return <></>;
};

import { useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

import { authenticationSession } from '@/lib/authentication-session';

const AuthenticatePage = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const searchParams = new URLSearchParams(location.search);
  const response = searchParams.get('response');

  useEffect(() => {
    if (response) {
      const decodedResponse = JSON.parse(response);
      authenticationSession.saveResponse(decodedResponse, false);
      navigate('/flows');
    }
  }, [response]);

  return <>Please wait...</>;
};

export default AuthenticatePage;

import {
  AppConnectionScope,
  AppConnectionStatus,
  AppConnectionWithoutSensitiveData,
  Permission,
  PlatformRole,
} from '@activepieces/shared';
import { ColumnDef } from '@tanstack/react-table';
import { t } from 'i18next';
import {
  CheckIcon,
  Globe,
  Trash2,
  Clock,
  Activity,
  Workflow,
  Puzzle,
} from 'lucide-react';
import { useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import { NewConnectionDialog } from '@/app/connections/new-connection-dialog';
import { ReconnectButtonDialog } from '@/app/connections/reconnect-button-dialog';
import { ReplaceConnectionsDialog } from '@/app/connections/replace-connections-dialog';
import { AnimatedIconButton } from '@/components/custom/animated-icon-button';
import { CopyTextTooltip } from '@/components/custom/clipboard/copy-text-tooltip';
import {
  BulkAction,
  CURSOR_QUERY_PARAM,
  DataTable,
  DataTableFilters,
  LIMIT_QUERY_PARAM,
  RowDataWithActions,
} from '@/components/custom/data-table';
import { DataTableColumnHeader } from '@/components/custom/data-table/data-table-column-header';
import { ConfirmationDeleteDialog } from '@/components/custom/delete-dialog';
import { FormattedDate } from '@/components/custom/formatted-date';
import { DeleteConnectionWarning } from '@/components/custom/global-connection-utils';
import { PermissionNeededTooltip } from '@/components/custom/permission-needed-tooltip';
import { StatusIconWithText } from '@/components/custom/status-icon-with-text';
import { PlusIcon } from '@/components/icons/plus';
import { ReplaceIcon } from '@/components/icons/replace';
import { Button } from '@/components/ui/button';
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/components/ui/tooltip';
import {
  EditGlobalConnectionDialog,
  RenameConnectionDialog,
  appConnectionsMutations,
  appConnectionsQueries,
  appConnectionUtils,
} from '@/features/connections';
import { PieceIconWithPieceName, piecesHooks } from '@/features/pieces';
import { useAuthorization } from '@/hooks/authorization-hooks';
import { ownerColumnHooks } from '@/hooks/owner-column-hooks';
import { userHooks } from '@/hooks/user-hooks';
import { authenticationSession } from '@/lib/authentication-session';
import { formatUtils } from '@/lib/format-utils';

function AppConnectionsPage() {
  const navigate = useNavigate();
  const [refresh, setRefresh] = useState(0);
  const [selectedRows, setSelectedRows] = useState<
    Array<AppConnectionWithoutSensitiveData>
  >([]);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const { checkAccess } = useAuthorization();
  const userPlatformRole = userHooks.getCurrentUserPlatformRole();
  const location = useLocation();
  const { pieces } = piecesHooks.usePieces({});
  const pieceOptions = (pieces ?? []).map((piece) => ({
    label: piece.displayName,
    value: piece.name,
  }));
  const projectId = authenticationSession.getProjectId()!;

  const searchParams = new URLSearchParams(location.search);
  const cursor = searchParams.get(CURSOR_QUERY_PARAM) ?? undefined;
  const limit = searchParams.get(LIMIT_QUERY_PARAM)
    ? parseInt(searchParams.get(LIMIT_QUERY_PARAM)!)
    : 10;
  const status = (searchParams.getAll('status') as AppConnectionStatus[]) ?? [];
  const pieceName = searchParams.get('pieceName') ?? undefined;
  const displayName = searchParams.get('displayName') ?? undefined;

  const {
    data: connections,
    isLoading: connectionsLoading,
    refetch,
  } = appConnectionsQueries.useAppConnections({
    request: {
      projectId,
      cursor,
      limit,
      status,
      pieceName,
      displayName,
    },
    extraKeys: [location.search, projectId],
  });

  const { mutateAsync: deleteConnections } =
    appConnectionsMutations.useBulkDeleteAppConnections(refetch);

  const filteredData = useMemo(() => {
    if (!connections?.data) return undefined;
    const searchParams = new URLSearchParams(location.search);
    const ownerEmails = searchParams.getAll('owner');

    if (ownerEmails.length === 0) return connections;

    return {
      data: connections.data.filter(
        (conn) => conn.owner && ownerEmails.includes(conn.owner.email),
      ),
      next: connections.next,
      previous: connections.previous,
    };
  }, [connections, location.search]);

  const userHasPermissionToWriteAppConnection = checkAccess(
    Permission.WRITE_APP_CONNECTION,
  );
  const { data: owners } = appConnectionsQueries.useConnectionsOwners();
  const filters: DataTableFilters<keyof AppConnectionWithoutSensitiveData>[] =
    ownerColumnHooks.useOwnerColumnFilter<AppConnectionWithoutSensitiveData>(
      [
        {
          type: 'select',
          title: t('Status'),
          accessorKey: 'status',
          options: Object.values(AppConnectionStatus).map((status) => {
            return {
              label: formatUtils.convertEnumToHumanReadable(status),
              value: status,
            };
          }),
          icon: CheckIcon,
        },
        {
          type: 'select',
          title: t('Pieces'),
          accessorKey: 'pieceName',
          icon: Puzzle,
          options: pieceOptions,
        },
        {
          type: 'input',
          title: t('Name'),
          accessorKey: 'displayName',
          icon: Puzzle,
        },
      ],
      4,
      owners,
    );

  const columns: ColumnDef<
    RowDataWithActions<AppConnectionWithoutSensitiveData>,
    unknown
  >[] = ownerColumnHooks.useOwnerColumn<AppConnectionWithoutSensitiveData>(
    [
      {
        accessorKey: 'displayName',
        size: 280,
        header: ({ column }) => (
          <DataTableColumnHeader
            column={column}
            title={t('Name')}
            icon={Puzzle}
          />
        ),
        cell: ({ row }) => {
          const isPlatformConnection = row.original.scope === 'PLATFORM';
          return (
            <div className="flex items-center gap-2">
              <CopyTextTooltip
                title={t('External ID')}
                text={row.original.externalId || ''}
              >
                <div className="flex items-center gap-2 w-fit">
                  <PieceIconWithPieceName
                    pieceName={row.original.pieceName}
                    showTooltip={false}
                    size="sm"
                  />
                  <span className="truncate max-w-[120px] 2xl:max-w-[250px]">
                    {row.original.displayName}
                  </span>
                </div>
              </CopyTextTooltip>
              {isPlatformConnection && (
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Globe className="w-4 h-4 shrink-0" />
                  </TooltipTrigger>
                  <TooltipContent>
                    <p>
                      {t(
                        'This connection is global and can be managed in the platform admin',
                      )}
                    </p>
                  </TooltipContent>
                </Tooltip>
              )}
            </div>
          );
        },
      },
      {
        accessorKey: 'status',
        size: 120,
        header: ({ column }) => (
          <DataTableColumnHeader
            column={column}
            title={t('Status')}
            icon={Activity}
          />
        ),
        cell: ({ row }) => {
          const status = row.original.status;
          const { variant, icon: Icon } =
            appConnectionUtils.getStatusIcon(status);
          return (
            <div className="text-left">
              <StatusIconWithText
                icon={Icon}
                text={formatUtils.convertEnumToHumanReadable(status)}
                variant={variant}
              />
            </div>
          );
        },
      },
      {
        accessorKey: 'updated',
        size: 150,
        header: ({ column }) => (
          <DataTableColumnHeader
            column={column}
            title={t('Connected At')}
            icon={Clock}
          />
        ),
        cell: ({ row }) => {
          return (
            <div className="text-left">
              <FormattedDate date={new Date(row.original.updated)} />
            </div>
          );
        },
      },
      {
        accessorKey: 'flowCount',
        size: 80,
        header: ({ column }) => (
          <DataTableColumnHeader
            column={column}
            title={t('Flows')}
            icon={Workflow}
          />
        ),
        cell: ({ row }) => {
          return (
            <div
              className="text-left underline cursor-pointer"
              onClick={() => {
                navigate(
                  `/flows?connectionExternalId=${row.original.externalId}`,
                );
              }}
            >
              {row.original.flowIds?.length}
            </div>
          );
        },
      },
      {
        id: 'actions',
        size: 100,
        cell: ({ row }) => {
          const isPlatformConnection =
            row.original.scope === AppConnectionScope.PLATFORM;
          const userHasPermissionToRename = isPlatformConnection
            ? userPlatformRole === PlatformRole.ADMIN
            : userHasPermissionToWriteAppConnection;
          return (
            <div className="flex items-center gap-2 justify-end">
              {row.original.scope === AppConnectionScope.PROJECT ? (
                <RenameConnectionDialog
                  connectionId={row.original.id}
                  currentName={row.original.displayName}
                  onRename={() => {
                    refetch();
                  }}
                  userHasPermissionToRename={userHasPermissionToRename}
                />
              ) : (
                <EditGlobalConnectionDialog
                  connectionId={row.original.id}
                  currentName={row.original.displayName}
                  projectIds={row.original.projectIds}
                  userHasPermissionToEdit={userHasPermissionToRename}
                  onEdit={() => {
                    refetch();
                  }}
                  preSelectForNewProjects={
                    row.original.preSelectForNewProjects ?? false
                  }
                />
              )}
              <ReconnectButtonDialog
                hasPermission={userHasPermissionToRename}
                connection={row.original}
                onConnectionCreated={() => {
                  refetch();
                }}
              />
            </div>
          );
        },
      },
    ],
    4,
  );

  const bulkActions: BulkAction<AppConnectionWithoutSensitiveData>[] = useMemo(
    () => [
      {
        render: (_, resetSelection) => {
          return (
            <>
              {selectedRows.length > 0 && (
                <ConfirmationDeleteDialog
                  title={t('Delete Connections')}
                  message={t(
                    'The selected connections will be permanently deleted.',
                  )}
                  warning={<DeleteConnectionWarning />}
                  mutationFn={async () => {
                    await deleteConnections(selectedRows.map((row) => row.id));
                    refetch();
                    resetSelection();
                    setSelectedRows([]);
                  }}
                  entityName={t('connection')}
                  buttonText={t('Delete')}
                  open={showDeleteDialog}
                  onOpenChange={setShowDeleteDialog}
                  showToast
                >
                  <Button
                    variant="ghost"
                    size="sm"
                    className="text-destructive hover:text-destructive"
                    onClick={() => setShowDeleteDialog(true)}
                  >
                    <Trash2 className="h-4 w-4 mr-1" />
                    {t('Delete')} ({selectedRows.length})
                  </Button>
                </ConfirmationDeleteDialog>
              )}
            </>
          );
        },
      },
    ],
    [selectedRows, showDeleteDialog],
  );

  const toolbarButtons = useMemo(
    () => [
      <PermissionNeededTooltip
        key="replace"
        hasPermission={userHasPermissionToWriteAppConnection}
      >
        <ReplaceConnectionsDialog
          projectId={projectId}
          onConnectionMerged={() => {
            setRefresh(refresh + 1);
            refetch();
          }}
        >
          <AnimatedIconButton
            icon={ReplaceIcon}
            iconSize={16}
            variant="outline"
            disabled={!userHasPermissionToWriteAppConnection}
          >
            {t('Replace')}
          </AnimatedIconButton>
        </ReplaceConnectionsDialog>
      </PermissionNeededTooltip>,
      <PermissionNeededTooltip
        key="new"
        hasPermission={userHasPermissionToWriteAppConnection}
      >
        <NewConnectionDialog
          isGlobalConnection={false}
          onConnectionCreated={() => {
            setRefresh(refresh + 1);
            refetch();
          }}
        >
          <AnimatedIconButton
            icon={PlusIcon}
            iconSize={16}
            size="sm"
            disabled={!userHasPermissionToWriteAppConnection}
          >
            {t('New Connection')}
          </AnimatedIconButton>
        </NewConnectionDialog>
      </PermissionNeededTooltip>,
    ],
    [userHasPermissionToWriteAppConnection, refresh],
  );
  return (
    <div className="flex-col w-full">
      <DataTable
        emptyStateTextTitle={t('No connections found')}
        emptyStateTextDescription={t(
          'Come back later when you create a automation to manage your connections',
        )}
        emptyStateIcon={<Globe className="size-14" />}
        columns={columns}
        page={filteredData}
        isLoading={connectionsLoading}
        filters={filters}
        selectColumn={true}
        onSelectedRowsChange={setSelectedRows}
        bulkActions={bulkActions}
        toolbarButtons={toolbarButtons}
      />
    </div>
  );
}

