                ))}
              </SelectContent>
            </Select>
          </div>
          <Button
            variant="ghost"
            size="sm"
            className="gap-1"
            onClick={() => {
              if (clientPagination) {
                table.previousPage();
              } else {
                setCurrentCursor(previousPageCursor);
