    </div>
  );
}

import { isNil } from '@activepieces/shared';
import { useState, useRef, useCallback } from 'react';

import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/components/ui/tooltip';

type EditableTextProps = {
  value: string | undefined;
  className?: string;
  readonly: boolean;
  onValueChange: (value: string) => void;
  tooltipContent?: string;
  disallowEditingOnClick?: boolean;
  isEditing: boolean;
  setIsEditing: (isEditing: boolean) => void;
};

const EditableText = ({
  value: initialValue,
  className = '',
  readonly = false,
  onValueChange,
  tooltipContent,
  disallowEditingOnClick,
  isEditing,
  setIsEditing,
}: EditableTextProps) => {
  const [value, setValue] = useState(initialValue);
  const isEditingPreviousRef = useRef(false);
  const valueOnEditingStartedRef = useRef(initialValue);

  if (value !== initialValue) {
    setValue(initialValue);
  }
  const editableTextRef = useRef<HTMLDivElement>(null);

  const emitChangedValue = useCallback(() => {
    const nodeValue = (editableTextRef.current?.textContent ?? '').trim();
    const shouldUpdateValue =
      nodeValue.length > 0 && nodeValue !== valueOnEditingStartedRef.current;

    setValue(shouldUpdateValue ? nodeValue : valueOnEditingStartedRef.current);
    if (shouldUpdateValue) {
      onValueChange(nodeValue);
    }
  }, [onValueChange, valueOnEditingStartedRef.current]);

  const setSelectionToValue = () => {
    requestAnimationFrame(() => {
      if (
        editableTextRef.current &&
        window.getSelection &&
        document.createRange
      ) {
        const range = document.createRange();
        const sel = window.getSelection();
        range.selectNodeContents(editableTextRef.current);
        sel?.removeAllRanges();
        sel?.addRange(range);
      }
    });
  };

  if (isEditing && !isEditingPreviousRef.current) {
    valueOnEditingStartedRef.current = value ? value.trim() : '';

    setSelectionToValue();
  }
  isEditingPreviousRef.current = isEditing;

  return !isEditing ? (
    <Tooltip>
      <TooltipTrigger
        disabled={
          readonly ||
          isEditing ||
          disallowEditingOnClick ||
          isNil(tooltipContent)
        }
        asChild
      >
        <div
          onClick={() => {
            if (!isEditing && !readonly && !disallowEditingOnClick) {
              setIsEditing(true);
            }
          }}
          ref={editableTextRef}
          key={'viewed'}
          className={`${className} truncate `}
          title={
            editableTextRef.current &&
            editableTextRef.current.scrollWidth >
              editableTextRef.current.clientWidth &&
            value
              ? value
              : ''
          }
        >
          {value}
        </div>
      </TooltipTrigger>
      {tooltipContent && (
        <TooltipContent className="font-normal z-50" side="bottom">
          {tooltipContent}
        </TooltipContent>
      )}
    </Tooltip>
  ) : (
    <div
      key={'editable'}
      ref={editableTextRef}
      contentEditable
      suppressContentEditableWarning={true}
      className={`${className}  focus:outline-hidden break-all`}
      onBlur={() => {
        emitChangedValue();
        setIsEditing(false);
      }}
      onKeyDown={(event) => {
        if (event.key === 'Escape') {
          setValue(valueOnEditingStartedRef.current);
          setIsEditing(false);
        } else if (event.key === 'Enter') {
          emitChangedValue();
          setIsEditing(false);
        }
      }}
    >
      {value}
    </div>
  );
};

EditableText.displayName = 'EditableText';
export default EditableText;

'use client';

import { isNil } from '@activepieces/shared';
import * as React from 'react';

import { cn } from '@/lib/utils';

import { TimePeriodSelect } from './time-period-select';
import { Period } from './time-picker-utils';
import { TimeUnitPickerInput } from './time-unit-input';

interface TimePickerProps {
  date: Date | undefined;
  setDate: (date: Date) => void;
  showSeconds?: boolean;
  name?: string;
}

const minutesItems = new Array(60).fill(0).map((_, index) => ({
  value: index.toString(),
  label: index < 10 ? `0${index}` : index.toString(),
}));

const hoursItems = new Array(12).fill(0).map((_, index) => ({
  value: (index + 1).toString(),
  label: index + 1 < 10 ? `0${index + 1}` : (index + 1).toString(),
}));

export function TimePicker({
  date,
  setDate,
  showSeconds,
  name = 'from',
}: TimePickerProps) {
  const [period, setPeriod] = React.useState<Period>(() => {
    if (date) {
      return date.getHours() >= 12 ? 'PM' : 'AM';
    }
    return name === 'from' ? 'AM' : 'PM';
  });
  React.useEffect(() => {
    if (date && date.getHours() >= 12) {
      setPeriod('PM');
    } else if (!date) {
      setPeriod(name === 'from' ? 'AM' : 'PM');
    }
  }, [date]);
  const hasValueChanged =
    name === 'from'
      ? date?.getHours() !== 0 || date?.getMinutes() !== 0 || period !== 'AM'
      : date?.getHours() !== 23 || date?.getMinutes() !== 59 || period !== 'PM';
  const isActive = !isNil(date) && hasValueChanged;
  const minuteRef = React.useRef<HTMLInputElement>(null);
  const hourRef = React.useRef<HTMLInputElement>(null);
  const secondRef = React.useRef<HTMLInputElement>(null);
  const periodRef = React.useRef<HTMLButtonElement>(null);

  return (
    <div
      className={cn(
        'flex items-center transition-all  gap-2 w-full text-muted-foreground justify-center bg-accent/50 py-1 px-2 rounded-sm h-[43px] border border-solid border-border',
        {
          'text-foreground': isActive,
        },
      )}
    >
      <div className="grid gap-1 text-center">
        <TimeUnitPickerInput
          picker="12hours"
          isActive={isActive}
          period={period}
          date={date}
          setDate={setDate}
          name={name}
          ref={hourRef}
          onRightFocus={() => minuteRef.current?.focus()}
          autoCompleteList={hoursItems}
        />
      </div>
      :
      <div className="grid gap-1 text-center">
        <TimeUnitPickerInput
          picker="minutes"
          id="minutes12"
          isActive={isActive}
          name={name}
          date={date}
          period={period}
          setDate={setDate}
          ref={minuteRef}
          onLeftFocus={() => hourRef.current?.focus()}
          onRightFocus={() => secondRef.current?.focus()}
          autoCompleteList={minutesItems}
        />
      </div>
      {showSeconds && (
        <>
          :
          <div className="grid gap-1 text-center">
            <TimeUnitPickerInput
              picker="seconds"
              id="seconds12"
              name={name}
              isActive={isActive}
              date={date}
              setDate={setDate}
              ref={secondRef}
              onLeftFocus={() => minuteRef.current?.focus()}
              onRightFocus={() => periodRef.current?.focus()}
            />
          </div>
        </>
      )}
      <div className="grid gap-1 text-center">
        <TimePeriodSelect
          period={period}
          isActive={isActive}
          setPeriod={setPeriod}
          date={date}
          setDate={setDate}
          ref={periodRef}
          onLeftFocus={() => secondRef.current?.focus()}
        />
      </div>
    </div>
  );
}

import {
  ApFlagId,
  isNil,
  TelemetryEvent,
  UserWithMetaInformation,
} from '@activepieces/shared';
import { AnalyticsBrowser } from '@segment/analytics-next';
import posthog from 'posthog-js';
import React, { useEffect, useState, useRef } from 'react';
import { useDeepCompareEffect } from 'react-use';

import { flagsHooks } from '@/hooks/flags-hooks';
import { userHooks } from '@/hooks/user-hooks';

interface TelemetryProviderProps {
  children: React.ReactNode;
}

const TelemetryProvider = ({ children }: TelemetryProviderProps) => {
  const { data: currentUser } = userHooks.useCurrentUser();
  const [analytics, setAnalytics] = useState<AnalyticsBrowser | null>(null);
  const initializedUserEmail = useRef<string | null>(null);

  const [user, setUser] = useState<UserWithMetaInformation | null>(
    currentUser ?? null,
  );
  const { data: telemetryEnabled } = flagsHooks.useFlag<boolean>(
    ApFlagId.TELEMETRY_ENABLED,
  );
  const { data: flagCurrentVersion } = flagsHooks.useFlag<string>(
    ApFlagId.CURRENT_VERSION,
  );
  const { data: flagEnvironment } = flagsHooks.useFlag<string>(
    ApFlagId.ENVIRONMENT,
  );

  useEffect(() => {
    const handleStorageChange = (_event: StorageEvent) => {
      setUser(currentUser ?? null);
    };

    window.addEventListener('storage', handleStorageChange);

    return () => {
      window.removeEventListener('storage', handleStorageChange);
    };
  }, []);

  useDeepCompareEffect(() => {
    if (isNil(user)) {
      return;
    }

    if (telemetryEnabled && user?.email !== initializedUserEmail.current) {
      initTelemetry();
    }
  }, [telemetryEnabled, user]);

  const initTelemetry = () => {
    if (isNil(user)) {
      return;
    }
    console.log('Telemetry enabled');
    const newAnalytics = AnalyticsBrowser.load({
      writeKey: 'Znobm6clOFLZNdMFpZ1ncf6VDmlCVSmj',
    });

    newAnalytics.addSourceMiddleware(({ payload, next }) => {
      const path = payload?.obj?.properties?.['path'];
      const ignoredPaths = ['/embed'];
      if (ignoredPaths.includes(path)) {
        return;
      }
      next(payload);
    });

    const currentVersion = flagCurrentVersion || '0.0.0';
    const environment = flagEnvironment || '0.0.0';

    newAnalytics.identify(user.id, {
      email: user.email,
      firstName: user.firstName,
      lastName: user.lastName,
      activepiecesVersion: currentVersion,
      activepiecesEnvironment: environment,
      ui: 'react',
    });

    newAnalytics.ready(() => {
      posthog.init('phc_7F92HoXJPeGnTKmYv0eOw62FurPMRW9Aqr0TPrDzvHh', {
        autocapture: false,
        capture_pageview: false,
        segment: (window as any).analytics,
        loaded: () => newAnalytics.page(),
      });

      posthog.identify(user.id, {
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        activepiecesVersion: currentVersion,
        activepiecesEnvironment: environment,
      });
    });
    setAnalytics(newAnalytics);
    initializedUserEmail.current = user.email;
  };

  const reset = () => {
    if (analytics) {
      analytics.reset();
    }
    posthog.reset();
    console.log('Telemetry removed');
    initializedUserEmail.current = null;
  };

  const capture = (event: TelemetryEvent) => {
    if (telemetryEnabled && analytics) {
      analytics.track(event.name, event.payload);
    }
  };

  return (
    <TelemetryContext.Provider value={{ capture, reset }}>
      {children}
    </TelemetryContext.Provider>
  );
};

interface TelemetryContextType {
  capture: (event: TelemetryEvent) => void;
  reset: () => void;
}

const TelemetryContext = React.createContext<TelemetryContextType>({
  capture: () => {},
  reset: () => {},
});

export const useTelemetry = () => React.useContext(TelemetryContext);

export default TelemetryProvider;

'use client';

import { isNil } from '@activepieces/shared';
import { useVirtualizer } from '@tanstack/react-virtual';
import * as React from 'react';

import { cn } from '@/lib/utils';

import { ScrollArea } from './scroll-area';

interface VirtualizedScrollAreaProps<T> {
  items: T[];
  renderItem: (item: T, index: number) => React.ReactNode;
  overscan?: number;
  estimateSize: (index: number) => number;
  getItemKey?: (index: number) => string | number;
  className?: string;
  initialScroll?: {
    index: number;
    clickAfterScroll: boolean;
  };
}

export interface VirtualizedScrollAreaRef {
  scrollToIndex: (
    index: number,
    options?: {
      align?: 'start' | 'center' | 'end';
      behavior?: 'auto' | 'smooth';
    },
  ) => void;
}

const VirtualizedScrollArea = <T,>({
  items,
  renderItem,
  overscan = 5,
  estimateSize,
  getItemKey,
  initialScroll,
  className,
  ...props
}: VirtualizedScrollAreaProps<T>) => {
  const scrollAreaViewportRef = React.useRef<HTMLDivElement>(null);

  const rowVirtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => scrollAreaViewportRef.current,
    estimateSize: estimateSize,
    overscan,
    getItemKey: getItemKey || ((index) => index),
  });

  const virtualItems = rowVirtualizer.getVirtualItems();
  React.useEffect(() => {
    if (isNil(initialScroll)) {
      return;
    }
    if (initialScroll.index > -1) {
      rowVirtualizer.scrollToIndex(initialScroll.index, {
        align: 'start',
        behavior: 'auto',
      });
      if (initialScroll?.clickAfterScroll) {
        //need to wait for the scroll to be completed
        setTimeout(() => {
          const targetElement = scrollAreaViewportRef.current?.querySelector(
            `[data-virtual-index="${initialScroll.index}"]`,
          );
          const renderedElement = targetElement?.children[0];
          if (renderedElement instanceof HTMLElement) {
            renderedElement.click();
          }
        }, 100);
      }
    }
  }, [rowVirtualizer]);
  return (
    <ScrollArea
      viewPortRef={scrollAreaViewportRef}
      {...props}
      className={cn('h-full', className)}
    >
      <div
        style={{
          height: `${rowVirtualizer.getTotalSize()}px`,
          width: '100%',
          position: 'relative',
        }}
      >
        {virtualItems.map((virtualItem) => (
          <div
            key={virtualItem.key}
            data-virtual-index={virtualItem.index}
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '100%',
              height: `${virtualItem.size}px`,
              transform: `translateY(${virtualItem.start}px)`,
            }}
          >
            {renderItem(items[virtualItem.index], virtualItem.index)}
          </div>
        ))}
      </div>
    </ScrollArea>
  );
};

export { VirtualizedScrollArea };

import { AgentTool, isNil, mcpToolNameUtils } from '@activepieces/shared';
import Fuse from 'fuse.js';
import { t } from 'i18next';
import { Search } from 'lucide-react';
import React, { useMemo, useState } from 'react';
import { useDebounce } from 'use-debounce';

import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';

import { usePieceToolsDialogStore } from '../../stores/pieces-tools';

interface PieceActionsDialogProps {
  tools: AgentTool[];
}

export const PieceActionsList: React.FC<PieceActionsDialogProps> = ({
  tools,
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 200);
  const { handleActionSelect, selectedPiece } = usePieceToolsDialogStore();

  const selectedActionNames = useMemo(
    () => new Set(tools.map((tool) => tool.toolName)),
    [tools],
  );

  const fuse = useMemo(() => {
    if (isNil(selectedPiece) || isNil(selectedPiece.suggestedActions))
      return null;

    return new Fuse(selectedPiece.suggestedActions, {
      keys: [
        { name: 'displayName', weight: 0.8 },
        { name: 'description', weight: 0.2 },
      ],
      threshold: 0.35,
      ignoreLocation: true,
    });
  }, [selectedPiece?.suggestedActions]);

  const filteredActions = useMemo(() => {
    if (!debouncedQuery.trim() || isNil(fuse))
      return selectedPiece?.suggestedActions || [];

    return fuse.search(debouncedQuery).map((r) => r.item);
  }, [debouncedQuery, fuse, selectedPiece?.suggestedActions]);

  if (isNil(selectedPiece)) {
    return <p>{t('No app is selected')}</p>;
  }

  return (
    <ScrollArea className="overflow-y-auto">
      <div className="px-4 py-3 border-b">
        <div className="relative border rounded-sm">
          <Search className="absolute left-2 top-2.5 size-4 text-muted-foreground" />
          <Input
            placeholder={t('Search')}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-9 shadow-none border-none"
          />
        </div>
      </div>

      <div className="flex p-4 flex-col gap-2">
        {filteredActions.map((action) => {
          const isDisabled = selectedActionNames.has(
            mcpToolNameUtils.createPieceToolName(
              selectedPiece.pieceName,
              action.name,
            ),
          );

          return (
            <div
              key={action.name}
              className={`
                p-2 flex items-center gap-x-2 rounded-lg transition
                ${
                  isDisabled
                    ? 'opacity-50 cursor-not-allowed'
                    : 'hover:bg-accent cursor-pointer'
                }
              `}
              onClick={() => {
                if (!isDisabled) {
                  handleActionSelect(action);
                }
              }}
            >
              <div className="flex gap-2">
                <div className="size-9 flex items-center justify-center rounded-sm border bg-background">
                  <img
                    className="size-6 object-contain"
                    src={selectedPiece.logoUrl}
                    alt={selectedPiece.displayName}
                  />
                </div>

                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-sm">
                      {action.displayName}
                    </span>

                    {isDisabled && (
                      <span className="text-xs text-muted-foreground">
                        {t('(Already added)')}
                      </span>
                    )}
                  </div>

                  {action.description && (
                    <div className="text-xs text-muted-foreground mt-0.5 line-clamp-2">
                      {action.description}
                    </div>
                  )}
                </div>
              </div>
            </div>
          );
        })}

        {filteredActions.length === 0 && (
          <div className="text-center text-muted-foreground py-8">
            {t('No actions found')}
          </div>
        )}
      </div>
    </ScrollArea>
  );
};

