                    </PopoverHeader>
                    <PasswordRequirementsList
                      password={field.value ?? ''}
                      isSubmitted={form.formState.submitCount > 0}
                    />
                  </PopoverContent>
                </Popover>
                <FormMessage />
              </FormItem>
            )}
          />
          {showNewsLetterCheckbox && (
            <FormField
              control={form.control}
              name="newsLetter"
              render={({ field }) => (
                <FormItem className="flex items-center gap-2 ">
                  <FormControl>
