const extraIconVariants = cva(
  'flex items-center justify-center rounded-md bg-background border border-solid text-xs select-none',
  {
    variants: {
      size: {
        xxl: 'size-[64px]',
        xl: 'size-[48px]',
        lg: 'size-[40px]',
        md: 'size-[38px]',
        sm: 'size-[25px]',
        xs: 'size-[25px]',
      },
    },
  },
);

export function PieceIconList({
  maxNumberOfIconsToShow,
  trigger,
  size,
  className,
  background,
  excludeCore = false,
}: {
  trigger: FlowTrigger;
  maxNumberOfIconsToShow: number;
  size?: 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'xxl';
  className?: string;
  background?: string;
  excludeCore?: boolean;
}) {
  const steps = flowStructureUtil.getAllSteps(trigger);

  const { pieceNames, coreMetadata } = useMemo(
    () => extractPieceNamesAndCoreMetadata(steps, excludeCore),
    [steps, excludeCore],
  );

  const pieceQueries = piecesHooks.useMultiplePieces({ names: pieceNames });

  const stepsMetadata: StepMetadata[] = useMemo(() => {
    const pieceMetadata: StepMetadata[] = pieceQueries
      .map((q) => q.data)
      .filter((data): data is NonNullable<typeof data> => !!data)
      .filter(
        (piece) =>
          !excludeCore || !piece.categories?.includes(PieceCategory.CORE),
      )
      .map((piece) => ({
        displayName: piece.displayName,
        logoUrl: piece.logoUrl,
        description: piece.description,
        type: FlowActionType.PIECE as const,
        pieceType: piece.pieceType,
        pieceName: piece.name,
        pieceVersion: piece.version,
        categories: piece.categories ?? [],
        packageType: piece.packageType,
        auth: piece.auth,
      }));
    return [...coreMetadata, ...pieceMetadata];
  }, [pieceQueries.map((q) => q.dataUpdatedAt).join(','), coreMetadata]);

  const uniqueMetadata: StepMetadata[] = stepsMetadata.filter(
    (item, index, self) =>
      self.findIndex(
        (secondItem) => item.displayName === secondItem.displayName,
      ) === index,
  );
  const visibleMetadata = uniqueMetadata.slice(0, maxNumberOfIconsToShow);
  const extraPieces = uniqueMetadata.length - visibleMetadata.length;
  const extraMetadata = uniqueMetadata.slice(maxNumberOfIconsToShow);

  return (
    <div className={className || 'flex gap-0.5 '}>
      {visibleMetadata.map((metadata) => (
        <PieceIcon
          logoUrl={metadata.logoUrl}
          showTooltip={true}
          size={size ?? 'md'}
          border={true}
          displayName={metadata.displayName}
          key={metadata.displayName}
          background={background}
        />
      ))}
      {extraPieces > 0 && (
        <Tooltip>
          <TooltipTrigger asChild>
            <div className={extraIconVariants({ size: size ?? 'xs' })}>
              +{extraPieces}
            </div>
          </TooltipTrigger>
          <TooltipContent side="bottom">
            {extraMetadata.length > 1 &&
              extraMetadata
                .map((m) => m?.displayName || '')
                .slice(0, -1)
                .join(', ') +
                ` ${t('and')} ${
                  extraMetadata[extraMetadata.length - 1].displayName
                }`}
            {extraMetadata.length === 1 && extraMetadata[0].displayName}
          </TooltipContent>
        </Tooltip>
      )}
    </div>
  );
}

import { t } from 'i18next';
import { useEffect, useRef, useState } from 'react';

import { Calendar } from '@/components/ui/calendar';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { formatUtils } from '@/lib/format-utils';
import { cn } from '@/lib/utils';

import { useCellContext } from './cell-context';

function isValidDate(date: string) {
  return !isNaN(new Date(date).getTime());
}
function getFormattedDate(date: string) {
  return isValidDate(date) ? formatUtils.formatDateOnly(new Date(date)) : '';
}
function DateEditor() {
  const { value, handleCellChange, setIsEditing, isEditing } = useCellContext();
  const [date, setDate] = useState<Date | undefined>(
    isValidDate(value) ? new Date(value) : undefined,
  );
  const [month, setMonth] = useState<Date | undefined>(
    isValidDate(value) ? new Date(value) : undefined,
  );
  const [inputValue, setInputValue] = useState(getFormattedDate(value));
  const handleSelect = (newDate: Date | undefined) => {
    setDate(newDate);
    if (newDate) {
      setInputValue(formatUtils.formatDateOnly(newDate));
      handleCellChange(newDate.toISOString());
      setIsEditing(false);
    }
  };

  const inputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (isEditing) {
      requestAnimationFrame(() => {
        inputRef.current?.focus();
      });
    } else {
      setInputValue(getFormattedDate(value));
    }
  }, [isEditing]);
  return (
    <div className="h-full w-full" ref={containerRef}>
      <Popover
        open={isEditing}
        onOpenChange={(open) => {
          if (!open) {
            setIsEditing(false);
          }
        }}
      >
        <PopoverTrigger asChild>
          <button
            className={cn(
              'w-full h-full flex items-center justify-between gap-2',
              'bg-background text-sm px-2',
              'focus:outline-hidden',
              {
                'border-2 border-primary': isEditing,
                'border-transparent bg-transparent!': !isEditing,
              },
            )}
          >
            {isEditing && (
              <input
                ref={inputRef}
                placeholder={t('mm/dd/yyy')}
                value={inputValue}
                type="text"
                onClick={(e) => {
                  e.stopPropagation();
                }}
                onChange={(e) => {
                  setInputValue(e.target.value);
                  if (isValidDate(e.target.value)) {
                    setDate(new Date(e.target.value));
                    setMonth(new Date(e.target.value));
                  } else {
                    setDate(undefined);
                  }
                }}
                onBlur={(e) => {
                  if (!containerRef.current?.contains(e.target as Node)) {
                    handleCellChange(date?.toISOString() ?? '');
                  }
                }}
                onKeyDown={(e) => {
                  e.stopPropagation();
                  if (e.key === 'Enter') {
                    handleCellChange(date?.toISOString() ?? '');
                    e.preventDefault();
                  }
                  if (e.key === 'Escape') {
                    setIsEditing(false);
                    e.preventDefault();
                  }
                }}
                className={cn(
                  'flex-1 h-full min-w-0',
                  'border-none text-sm px-2',
                  'focus:outline-hidden',
                  'placeholder:text-muted-foreground',
                  {
                    'border-transparent bg-transparent!': !isEditing,
                  },
                )}
                autoComplete="off"
              />
            )}
            {!isEditing && (
              <div className="flex grow h-full min-w-0">
                {getFormattedDate(value)}
              </div>
            )}
          </button>
        </PopoverTrigger>
        <PopoverContent className="w-auto p-0" align="start">
          <Calendar
            mode="single"
            selected={date}
            month={month}
            onMonthChange={setMonth}
            onSelect={handleSelect}
          />
        </PopoverContent>
      </Popover>
    </div>
  );
}

