import { FieldType } from '@activepieces/shared';
import { useEffect, useRef, useState } from 'react';
import { CalculatedColumn } from 'react-data-grid';
import { ErrorBoundary } from 'react-error-boundary';

import { cn } from '@/lib/utils';

import { ClientField } from '../stores/store/ap-tables-client-state';
import { Row } from '../types/types';

import { useTableState } from './ap-table-state-provider';
import { CellProvider } from './cell-context';
import { DateEditor } from './date-editor';
import { DropdownEditor } from './dropdown-editor';
import { NumberEditor } from './number-editor';
import { TextEditor } from './text-editor';

type EditableCellProps = {
  field: ClientField;
  value?: string;
  row: Row;
  onClick?: () => void;
  column: CalculatedColumn<Row, { id: string }>;
  rowIdx: number;
  disabled?: boolean;
  locked?: boolean;
};

const EditorSelector = ({ fieldType }: { fieldType: FieldType }) => {
  switch (fieldType) {
    case FieldType.DATE:
      return <DateEditor />;
    case FieldType.NUMBER:
      return <NumberEditor />;
    case FieldType.STATIC_DROPDOWN:
      return <DropdownEditor></DropdownEditor>;
    default:
      return <TextEditor />;
  }
};

const useSetInitialFocus = (isSelected: boolean) => {
  const containerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    requestAnimationFrame(() => {
      if (isSelected) {
        containerRef.current?.focus();
      }
    });
  }, []);
  return containerRef;
};

export function EditableCell({
  field,
  column,
  rowIdx,
  onClick,
  locked = false,
  value,
  disabled = false,
}: EditableCellProps) {
  const [selectedCell, setSelectedCell, records, fields] = useTableState(
    (state) => [
      state.selectedCell,
      state.setSelectedCell,
      state.records,
      state.fields,
    ],
  );
  const [isEditing, setIsEditing] = useState(false);
  const isSelected =
    selectedCell?.rowIdx === rowIdx && selectedCell?.columnIdx === column.idx;
  const containerRef = useSetInitialFocus(isSelected);
  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    const isTypingKey = e.key.length === 1 || e.key === 'Enter';
    if (isTypingKey && !disabled && !isEditing) {
      setIsEditing(true);
      setSelectedCell({ rowIdx, columnIdx: column.idx });
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        e.stopPropagation();
      }
      return;
    }
    // react data grid cells are all focusable and they have no api to prevent focus
    // so we need to prevent the default behavior of the arrow keys
    switch (e.key) {
      case 'ArrowUp': {
        if (rowIdx === 0) {
          e.preventDefault();
          e.stopPropagation();
        }
        break;
      }
      case 'ArrowDown': {
        if (rowIdx === records.length - 1) {
          e.preventDefault();
          e.stopPropagation();
        }
        break;
      }
      case 'ArrowLeft':
        if (column.idx === 1) {
          e.preventDefault();
          e.stopPropagation();
        }
        break;
      case 'ArrowRight': {
        if (column.idx === fields.length) {
          e.preventDefault();
          e.stopPropagation();
        }
      }
    }
  };
  const isDropdown = field.type === FieldType.STATIC_DROPDOWN;
  return (
    <div
      ref={containerRef}
      id={`editable-cell-${rowIdx}-${column.idx}`}
      className={
        isEditing
          ? 'h-full w-full'
          : cn(
              'h-full flex items-center justify-between gap-2  focus:outline-hidden  ',
              'group cursor-pointer border',
              isSelected && !locked ? 'border-primary' : 'border-transparent',
              locked && 'locked-row',
              !isDropdown && 'pl-2 py-2',
            )
      }
      tabIndex={0}
      onClick={() => {
        onClick?.();
        setSelectedCell({ rowIdx, columnIdx: column.idx });
      }}
      onFocus={() => {
        setSelectedCell({ rowIdx, columnIdx: column.idx });
      }}
      onDoubleClick={() => {
        if (!disabled) {
          setIsEditing(true);
        }
      }}
      onKeyDown={handleKeyDown}
    >
      <ErrorBoundary fallback={<div>Error</div>}>
        <CellProvider
          rowIdx={rowIdx}
          columnIdx={column.idx - 1}
          fieldType={field.type}
          value={value ?? ''}
          handleCellChange={() => {}}
          containerRef={containerRef}
          isEditing={isEditing}
          setIsEditing={setIsEditing}
          disabled={disabled}
        >
          <EditorSelector fieldType={field.type} />
        </CellProvider>
      </ErrorBoundary>
    </div>
  );
}

import { Field } from '@activepieces/shared';
import { t } from 'i18next';
import { ArrowLeftIcon } from 'lucide-react';
import { useEffect, useState } from 'react';

import { SearchableSelect } from '@/components/custom/searchable-select';
import { Input } from '@/components/ui/input';

import { FieldsMapping } from '../utils/utils';

const FieldsMappingControl = ({
  onChange,
  fields,
  csvColumns,
}: {
  onChange: (fieldsMapping: FieldsMapping) => void;
  fields: Field[];
  csvColumns: string[];
}) => {
  const initialFieldsMapping = Array(csvColumns.length)
    .fill(null)
    .map((_, index) => (index > fields.length - 1 ? null : fields[index].id));
  const [fieldsMapping, setFieldsMapping] =
    useState<FieldsMapping>(initialFieldsMapping);
  useEffect(() => {
    onChange(fieldsMapping);
  }, []);
  const csvColumnsOptions = [
    ...csvColumns.map((column, index) => ({
      label: column,
      value: index.toString(),
    })),
    { label: t('Ignored'), value: 'ignore' },
  ];
  const findFieldIdCsvIndex = (fieldId: string) => {
    const res = fieldsMapping.findIndex((id) => id === fieldId);
    if (res !== -1) {
      return res.toString();
    }
    return 'ignore';
  };
  const handleChange = (fieldId: string, columnIndex: string | null) => {
    const newFieldsMapping = [...fieldsMapping];
    const columnIndexUsingFieldId = findFieldIdCsvIndex(fieldId);
    if (columnIndexUsingFieldId !== 'ignore' || columnIndex === 'ignore') {
      newFieldsMapping[parseInt(columnIndexUsingFieldId)] = null;
    }
    if (columnIndex !== null && columnIndex !== 'ignore') {
      newFieldsMapping[parseInt(columnIndex)] = fieldId;
    }
    setFieldsMapping(newFieldsMapping);
    onChange(newFieldsMapping);
  };
  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-2">
        <div className="flex-1 text-center text-sm">{t('Table')}</div>
        <ArrowLeftIcon className=" w-4 h-4 opacity-0 shrink-0" />
        <div className="flex-1 text-center text-sm">{t('CSV')}</div>
      </div>
      {fields.map((field) => (
        <div className="flex items-center gap-2" key={field.id}>
          <div className="flex-1">
            <Input value={field.name} readOnly />
          </div>
          <ArrowLeftIcon className="w-4 h-4 shrink-0" />
          <div className="flex-1">
            <SearchableSelect
              options={csvColumnsOptions}
              onChange={(value) => handleChange(field.id, value)}
              value={findFieldIdCsvIndex(field.id)}
              placeholder={t('Field')}
              showDeselect={false}
            ></SearchableSelect>
          </div>
        </div>
      ))}
    </div>
  );
};

FieldsMappingControl.displayName = 'FieldsMappingControl';
export { FieldsMappingControl };

import { useEffect, useRef, useState } from 'react';

import { cn } from '@/lib/utils';

import { useCellContext } from './cell-context';

const NumberEditor = () => {
  const { value, handleCellChange, setIsEditing, isEditing } = useCellContext();
  const inputRef = useRef<HTMLInputElement>(null);
  const [inputValue, setInputValue] = useState(value);
  const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = event.target.value;
    setInputValue(newValue);
  };

  useEffect(() => {
    if (isEditing) {
      inputRef.current?.focus();
    } else {
      setInputValue(value);
    }
  }, [isEditing]);

  return (
    <div className="h-full relative w-full">
      <div
        className={cn('h-full flex items-center gap-2', {
          'border-2 border-primary': isEditing,
          'border-transparent': !isEditing,
        })}
      >
        {isEditing && (
          <input
            ref={inputRef}
            value={inputValue}
            type={'number'}
            onChange={handleChange}
            onBlur={() => {
              handleCellChange(inputValue);
            }}
            onKeyDown={(e) => {
              e.stopPropagation();
              if (e.key === 'Enter') {
                handleCellChange(inputValue);
                e.preventDefault();
              }
              if (e.key === 'Escape') {
                setIsEditing(false);
                e.preventDefault();
              }
            }}
            className={cn(
              'flex-1 h-full min-w-0',
              'border-none text-sm px-2',
              'focus:outline-hidden',
              'placeholder:text-muted-foreground',
            )}
            autoComplete="off"
          />
        )}
        {!isEditing && <div className="flex grow h-full w-full ">{value}</div>}
      </div>
    </div>
  );
};
NumberEditor.displayName = 'NumberEditor';
export { NumberEditor };

